+    }
+
+    let mut hasher = Sha256::new();
+    let mut exported_ids = Vec::new();
+    let mut issue_hashes = Vec::new();
+
+    for issue in &issues {
+        let json = match serde_json::to_string(issue) {
+            Ok(json) => json,
