+    let mut storage = test_db();
+
+    let blocker = fixtures::IssueBuilder::new("Blocker")
+        .with_type(IssueType::Bug)
+        .build();
+    let blocked_issue = fixtures::IssueBuilder::new("Blocked bug")
+        .with_type(IssueType::Bug)
